\usetikzlibrary{angles, quotes}
\begin{tikzpicture}[scale=1.5]
  % Equilateral triangle
  \coordinate (A) at (0, 0);
  \coordinate (B) at (5, 0);
  \coordinate (C) at (2.5, 4.33);
  \draw[very thick, fill=blue!10] (A) -- (B) -- (C) -- cycle;

  % Side lengths
  \node[below=0.4cm, font=\normalsize, fill=white, inner sep=2pt] at (2.5, 0) {5 cm};
  \node[above left=0.2cm, font=\normalsize, rotate=60, fill=white, inner sep=2pt] at (1.25, 2.17) {5 cm};
  \node[above right=0.2cm, font=\normalsize, rotate=-60, fill=white, inner sep=2pt] at (3.75, 2.17) {5 cm};

  % Equal side tick marks
  \draw[thick] (1.1, 1.9) -- (1.4, 2.1);
  \draw[thick] (1.0, 1.8) -- (1.3, 2.0);
  \draw[thick] (3.6, 2.1) -- (3.9, 1.9);
  \draw[thick] (3.7, 2.0) -- (4.0, 1.8);
  \draw[thick] (2.4, -0.2) -- (2.6, -0.2);
  \draw[thick] (2.4, -0.3) -- (2.6, -0.3);

  % Angle arcs and labels
  \draw[thick, red] (0.6, 0) arc (0:60:0.6);
  \node[red, font=\normalsize, fill=white, inner sep=2pt] at (1.0, 0.4) {$60^{\circ}$};

  \draw[thick, red] (4.4, 0) arc (180:120:0.6);
  \node[red, font=\normalsize, fill=white, inner sep=2pt] at (4.0, 0.4) {$60^{\circ}$};

  \draw[thick, red] (2.5, 3.73) arc (-90-60:-90+60:0.6);
  \node[red, font=\normalsize, fill=white, inner sep=2pt] at (2.5, 3.5) {$60^{\circ}$};

  % Classification
  \node[below=1.2cm, font=\large\bfseries, fill=white, inner sep=2pt] at (2.5, 0) {Equilateral Triangle};
  \node[below=2.0cm, font=\normalsize, fill=white, inner sep=2pt] at (2.5, 0) {All sides equal, all angles equal to $60^{\circ}$};
\end{tikzpicture}
